/*作者：@kuku（小红书同名）  */

/*⚠️ 禁二传二改·禁商用*/


/*错位修改教程（电脑、平板皆可食用）*/

/*1.只有标了《🍓》的区域是错位需要修改的*/

/*2.如遇气泡上半部分位移，只需调整头像区域的代码即可，调整到气泡顶部对准气泡中间部分*/

/*3.如遇气泡下半部分位移，需要到《气泡底部装饰图》区域修改数值，直到对准气泡中间区域即可*/

/*4.修改好记得点一下保存，否则切换主题后得重调⚠️⚠️⚠️*/



/* 头像区域 */
div[is_user] .mesAvatarWrapper { 
    position: absolute;
    top: -70px !important; /*控制char和user的头像上下位置🍓🍓*/
    left: 45% !important;/*控制char头像的左右位置🍓🍓*/
    transform: translateX(-50%);
    z-index: 2;
    margin: 0 !important;
}

/* 用户消息特异性修正 */
div[is_user="true"] .mesAvatarWrapper {
    top: -70px !important; /*控制user头像的左右位置🍓🍓*/
}



/* 头像尺寸调整*/
.avatar img {
    width: 80px !important;  /*控制头像大小*/
    height: 80px !important; /*控制头像位置大小，两条的数值一样才生效*/
    object-fit: cover !important; 
}



/* 气泡样式修改 */
.mes {
  background-color: var(--ui-color-main) !important;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.5);  /* 添加柔和阴影 */
  border-radius: 12px !important;  /* 加大圆角 */
  margin: 8px 0 !important;  /* 增加气泡间距 */
  transition: all 0.2s ease;  /* 添加过渡动画 */
}


/* 气泡背景图容器 */
.mes::before {
    content: "";
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: url("https://files.catbox.moe/ssy41u.jpg"); /* 替换为实际图片URL */
    background-size: cover;
    mix-blend-mode: multiply; /* 正片叠底混合 */
    opacity: 9; /* 图片透明度 */
    z-index: 1;
    border-radius: var(--box-border-radius); /* 继承圆角 */
}



/* 保证文本内容在图片上层 */
.mes_block {
    position: relative;
    z-index: 5;
}


/* 调整对话框基础尺寸 */
.mes {
    --bubble-width: 89%;  
    --vertical-spacing: 7rem; 

    width: var(--bubble-width) !important;
    min-height: var(--bubble-min-height);
    margin: var(--vertical-spacing) auto !important; 
    padding: 2rem 1rem !important; 
}


/* 框长度 */
.mes_text {
    padding: 1px 15px 110px 15px !important; /* 上 右 下 左 */
}



/* 头像背景图美化 */
.mesAvatarWrapper {
    position: relative; /* 建立定位上下文 */
    padding: 8px; /* 增加容器内边距 */
}

/* 自定义背景层 */
.mesAvatarWrapper::before {
    content: "";
    position: absolute;
    top: 280%;
    left: 74%;
    transform: translate(-50%, -50%);
    width: 528%; /* 图片覆盖范围 */
    height: 528%;
    background-image: url("https://files.catbox.moe/p1bfec.png"); /* 替换为实际图片URL */
    background-size: contain;
    background-repeat: no-repeat;

    mix-blend-mode: multiply; /* 正片叠底混合 */
    z-index: 1; /* 位于头像下方 */

}


/* 原头像层级提升 */
.avatar {
    position: relative;
    z-index: 2 !important; /* 确保头像在上层 */
    transform: scale(0.9); /* 适当缩小头像突出背景 */
    transition: 0.3s ease;
}



/* 头像下方装饰图美化 */
.mesAvatarWrapper {
    position: relative;
    margin-bottom: 20px; /* 增加底部间距 */
}

/* 装饰图容器 */
.avatar::after {
    content: "";
    position: absolute;
    bottom: -51px; /* 定位到头像下方 */
    left: 80%;
    transform: translateX(-50%);
    width: 135px; /* 图片宽度 */
    height: 135px; /* 图片高度 */
    background-image: url("https://files.catbox.moe/2yokel.gif");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 3; /* 高于头像层级 */
    filter: drop-shadow(0 2px 4px rgba(0,0,0,0.));

    pointer-events: none; /* 防止遮挡交互 */
}


/* 角色管理界面专属装饰图调整 */
#right-nav-panel .avatar::after { /* 限定角色管理面板 */
    width: 100px !important;       /* 尺寸缩小 */
    height: 100px !important;
    bottom: -14px !important;     /* 上移位置 */
    left: 50%;
    filter: 
        drop-shadow(0 1px 2px rgba(0,0,0,0.1)) 

}

@keyframes charPanelDeco {
    0%, 100% { transform: translateX(-50%) scale(0.95); }
    50% { transform: translateX(-50%) scale(1.05); }
}





/* 气泡底部装饰图🍓🍓🍓🍓 */
.mes {
    position: relative;

}

/* 动态装饰层 */
.mes::after {
    content: "";
    position: absolute;
    bottom: -261px; /*控制尾部气泡的上下位置🍓*/
    left: 49.8%;/*控制尾部气泡的左右位置🍓*/
    transform: translateX(-50%);
    width: 349px;/*控制尾部气泡的大小🍓*/
    height: 349px;/*控制尾部气泡的大小🍓*/
    background-image: url("https://files.catbox.moe/2xg96b.png");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 3; /* 确保在气泡下方 */

}

/* --------------🍚分割线🍚----------- */
/* 消息楼层定位调整 */
.mesIDDisplay {
    position: absolute !important;
    top: 60px !important; /* 垂直位置：负数表示移到气泡外上方 */
    left: -95px !important; /* 水平偏移量 */
    display: inline-block !important;
    font-size: 1em !important;
    padding: -10px -10px !important;
    z-index: 3 !important; /* 确保在装饰图之上 */
}

/* 时间戳位置调整 */
.mes_timer {
    position: absolute !important;
    top: 40px !important;       /* 垂直位置 */
    right: 120px !important;     /* 水平位置 */
    font-size: 1em !important;
    color: var(--text-color-sec) !important;
    opacity: 0.8;
    display: flex !important;
    align-items: center;
    gap: 6px;
    z-index: 2;
}


/* 词符数定位调整 */
.tokenCounterDisplay {
    position: absolute !important;
    bottom: 2px !important;    /* 与气泡底边距 */
    right: 110px !important;     /* 与气泡右边距 */
    display: flex !important;
    align-items: center;
    padding: 4px 8px !important;

    border-radius: 12px !important;

    font-size: 1em !important;
    z-index: 5 !important;
}


/* 添加在全局样式中 */
#top-bar {

   z-index: 1000; /* 确保顶部栏层级 */
}

/* 顶部装饰图容器 */
#top-bar::after {
    content: "";
    position: fixed;
    top: var(--topBar-height, -39px); /* 匹配顶部栏高度 */
    left: 0;
    width: 100%;
    height: 90px;
    background: url('https://files.catbox.moe/rxey4j.png') center/cover no-repeat;
    z-index: 999; /* 置于顶部栏下方 */
    pointer-events: none; /* 防止遮挡交互 */
    filter: opacity(0.) drop-shadow(0 2px 4px rgba(0,0,0,0.0));
}

/* 动态适配 */
@media (max-width: px) {
    #top-bar::after {
        height: 100px;
        background-size: auto 80%;
    }
}

/* 内容区下移 */
#main-content {
    margin-top: 150px; /* 等于装饰图高度 */
}


/* 滑块图案 */
input[type="range"]::-webkit-slider-thumb {
    width: 35px;
    height: 35px; 
    background: url('https://files.catbox.moe/m59etl.png') no-repeat center center; 
    background-size: contain; 
    border: none;
    border-radius: 0; 
    box-shadow: none;
    transition: width 0.2s, height 0.2s;
    z-index: 2;
}

/* 角色管理头像 */
#right-nav-panel .character_select .avatar {
    --avatar-base-size: 60px !important; /* 基础尺寸 */
    width: var(--avatar-base-size) !important;
    height: var(--avatar-base-size) !important;
    transform: scale(1) !important; /* 覆盖原有缩放 */
    margin: 8px auto !important; /* 居中留白 */
}

/* 头像图片尺寸同步调整 */
#right-nav-panel .character_select .avatar img {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover;
}


/*提示词*/

#completion_prompt_manager .completion_prompt_manager_footer {
    padding: 0;
}
#completion_prompt_manager #completion_prompt_manager_list {
    padding: 10px 15px 15px 15px;
    margin: 5px 0;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: var(--SmartThemeBodyColor);
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action:hover {
    filter: brightness(1.2);
    text-decoration: none;
}

#prompt-manager-reset-character, #completion_prompt_manager_popup .completion_prompt_manager_popup_entry_form_footer #completion_prompt_manager_popup_entry_form_reset {
    color: var(--customThemeColor-purple);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span,
#completion_prompt_manager .completion_prompt_manager_header_advanced span {
    filter: drop-shadow(0px 0px 2px var(--SmartThemeChatTintColor));
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
    border: 1px solid 1px solid var(--SmartThemeBorderColor);
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: var(--customThemeColor-purple);
}



/* 输入框 */
input[type="text"],
input[type="number"],
input[type="switch"],
input:not([type]),
textarea:not([type="search"]) {
    background-color: #fcf8db !important; 
    border-color: #734c4e !important; 
    transition: background-color 0.3s ease;
}


/* 深褐+淡青现代配色方案 */
:root {
  --tab-bg: rgba(91, 67, 67, 0.95);     /* 主背景深褐 */
  --tab-border: rgba(230, 255, 248, 0.4);  /* 淡青边框 */
  --tab-active-bg: rgba(91, 67, 67, 0.8); /* 激活状态深褐 */
  --tab-shadow: rgba(78, 57, 57, 0.15);  /* 深褐阴影 */
}

.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  background: 
    linear-gradient(165deg, 
      var(--tab-bg) 30%,
      color-mix(in srgb, var(--tab-bg) 70%, var(--tab-active-bg)) 100%
    ) !important;
  border: 1.2px solid var(--tab-border) !important;
  box-shadow: 
    0 3px 6px var(--tab-shadow),
    inset 2px 2px 4px rgba(230, 255, 248, 0.3), /* 淡青光内阴影 */
    inset -2px -2px 4px rgba(54, 39, 39, 0.2) !important;
  border-radius: 10px;
  backdrop-filter: blur(3px);
  transition: all 0.25s ease;
}

/* 文字适配 */
.standoutHeader strong,
.inline-drawer-header h4 {
  color: #E6FFF8 !important; /* 淡青文字 */
  text-shadow: 1px 1px 2px rgba(54, 39, 39, 0.4); /* 深褐阴影 */
}

/* 基础样式调整 */
.inline-drawer-header {
    background: linear-gradient(
        145deg, 
        rgba(91, 67, 67, 0.9) 30%, 
        rgba(91, 67, 67, 0.7) 100%
    ) !important;
    border: 1.5px solid rgba(230, 255, 248, 0.5) !important;
    border-radius: 8px !important;
    padding: 8px 32px 8px 12px !important;
    color: #E6FFF8 !important;
    box-shadow: 
        inset 2px 2px 4px rgba(230, 255, 248, 0.3),
        inset -2px -2px 4px rgba(54, 39, 39, 0.2),
        0 2px 4px rgba(78, 57, 57, 0.2) !important;
    transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}





/* 拟态风下拉框 */
select {
    background: #E6FFF8 !important;
    border: 2px solid rgba(91,67,67,) !important;
    border-radius: 90px !important;
    box-shadow: 
        4px 4px 8px rgba(91, 67, 67, 0.2),
        2px 2px 8px rgba(255,255,255,0.8) !important;
    padding: px 32px 8px 12px !important;
    color: #2C3E50 !important;
    appearance: none !important;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1) !important;
}

/* 聚焦状态微调 */
input[type="text"]:focus,
input[type="number"]:focus,
input[type="switch"]:focus,
input:not([type]):focus,
textarea:not([type="search"]):focus {
    border-color: #734c4e !important; /* 加深边框色 */
    box-shadow: 0 0 0 2px rgba(141, 222, 225, 0.3) !important;
}



/*ui背景图🍓🍓🍓*/
.drawer-content {
    background-image: url('https://files.catbox.moe/xe0qxj.jpg');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}


/* ---预设--- */
input[type="text"],
input[type="number"],
textarea:not([type="search"]):focus {

}

.text_pole:not(.objective-task) {
  background-color: var(--ui-color-sec);
  border: none;
}






/* 修改引用文本样式 */
blockquote,
.quote-style,
[class*="quote"] {
    background-color: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 0 !important;
    margin: 0.8em 0 !important;
}

/* 移除所有伪元素装饰 */
blockquote::before,
blockquote::after {
    content: "" !important;
}



/* 去除阴影 */
.mes_button,
.mes_edit_buttons,
#completion_prompt_manager
  #completion_prompt_manager_list
  li.completion_prompt_manager_prompt
  span
  span
  span {
  filter: none !important;
}

/* 禁用状态 */
input:disabled, 
select:disabled, 
textarea:disabled {
  background: rgba(237, 229, 216, 0.6) !important;
  color: #9E7C6E !important;
  border-style: dashed !important;
}

.drawer-icon::before,
#leftNavDrawerIcon::before,
#rightNavDrawerIcon::before {
    content: '';
    display: block;
    width: 40px;
    height: 40px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    margin-right: px;
    margin-left: -8px;
}
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 12px;
}

/* 调整图标容器样式 */
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 12px;
}





/* 强制非悬停状态完全不透明 */
.drawer-icon,
.fa-bars,
#extensionsMenuButton,
.fa-paper-plane {
  opacity: 1 !important;
  transition: opacity 0.2s ease !important;
}

/* 左侧导航图标 */
#leftNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/8vzowh.png');
}

/* 系统设置图标 */
#sys-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/ihcve4.png');
}

/* 高级格式图标 */
#advanced-formatting-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/8vzowh.png');
}

/* 世界信息图标 */
#WI-SP-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/ihcve4.png');
}

/* 用户设置图标 */
#user-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/8vzowh.png');
}

/* Logo图标 */
#logo_block .drawer-icon::before {
    background-image: url('https://files.catbox.moe/ihcve4.png');
}

/* 扩展设置图标 */
#extensions-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/8vzowh.png');
}

/* 角色管理图标 */
#persona-management-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/ihcve4.png');
}



/* 右侧导航图标 */
#rightNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/8vzowh.png');
}





/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/k5a2mf.png') center/contain no-repeat !important;
  width: 34px !important;
  height: 35px !important;
  filter: drop-shadow(0 0 3px rgba(139, 69, 19, 0.3));
}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/kw3ydt.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-top: 1px !important;
}

/* 发送按钮 */
.fa-paper-plane {
  background: url('https://files.catbox.moe/z3sdqo.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-left: 1px !important;
}

/* 隐藏特殊按钮的默认图标 */
/* Font Awesome类图标 */
.fa-bars::before,           /* 菜单按钮 */
.fa-ellipsis-v::before,     /* 垂直省略号 */
.fa-paper-plane::before,     /* 发送按钮 */
#extensionsMenuButton::before {  /* 扩展菜单 */
  display: none !important;
  content: '' !important;  /* 清除伪元素内容 */
}

/* 顶栏阴影 */
   body.no-blur #top-bar {
    box-shadow: none;
  }

/* 底栏QR按键隐藏 */#send_form:hover #qr--bar {    height: 40px;    transition: all 0.5s ease;}#qr--bar {    height: 0.1px;}
